// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Reopen Tasks
//------------------------------------------------------------------------------------------------------------------------
// 2.8.0 | 2022-06-07 | raj | STRY0122882 - Publish Task(s) button- New Modal to 'Choose Which Tasks to Publish'
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options) {
	main();

	function main() {
		// 2.8.0 | 2022-04-12 | mmcc | STRY0113587 - Mass Reopen Task Modal- Update Labels for UX
		// _buildMessages();
		// _setDataDefaults();

		if (input) {
			if (input.submit == true) {
				// STRY0114416 - 5 (glide record secur) run reopen tasks step
				var grSelectedTask = new GlideRecord('x_153465_discovert_route_task_instance');
				if (grSelectedTask.get(input.taskSysId)) {
					new Task_uiAction().uiAction_PublishDraftTasks(grSelectedTask, input.publishType);
				}

			} else {
				// 2.8.0 | 2022-04-12 | mmcc | STRY0113587 - Mass Reopen Task Modal- Update Labels for UX; reorder and added _getDescendantsCount()
				_setDataDefaults();
				_optCopy(['taskSysId']);
				_getDescendantsCount();
				_buildMessages();
			}
		}
	}

	// Use this function to get Messages that will be used in this widget
	function _buildMessages() {
		data.msgBodyAllSubtasks = gs.getMessage('Tasker - This Task and all {0} Subtasks',[data.descendantsCount]);
	}

	// get draft descendant count
	function _getDescendantsCount() {
		data.descendantsCount = 0;

		var taskerHelpers = new TaskerHelpers();
		data.descendantsCount = taskerHelpers.getDraftDescendantsCount(data.taskSysId);
	}

	// copy to data from input or options
	function _optCopy(names) {
		names.forEach(function(name) {
			data[name] = input[name] || options[name];
		});
	}

	// Use this function to set defaults
	function _setDataDefaults() {
		data.submit = false;
		// set a default radio button as selected
		data.publishType = 'taskOnly';
	}
})($sp, input, data, options);
